import json
import re
import sys

SRC = sys.argv[1]
OUT = sys.argv[2]
MAX_LEN = 1500

SYSTEM_REMINDER_RE = re.compile(r"<system-reminder>.*?</system-reminder>", re.DOTALL)
IDE_SELECTION_RE = re.compile(r"<ide_selection>.*?</ide_selection>", re.DOTALL)


def clean_text(text):
    if text is None:
        return ""
    text = SYSTEM_REMINDER_RE.sub("", text)
    text = IDE_SELECTION_RE.sub("", text)
    return text.strip()


def truncate(text, max_len=MAX_LEN):
    text = str(text)
    if len(text) <= max_len:
        return text
    return text[:max_len] + f"\n…[truncated, {len(text) - max_len} more characters]…"


def tool_result_text(content):
    if isinstance(content, str):
        return content
    if isinstance(content, list):
        parts = []
        for block in content:
            if not isinstance(block, dict):
                continue
            if block.get("type") == "text":
                parts.append(block.get("text", ""))
            elif block.get("type") == "tool_reference":
                parts.append(f"[tool schema loaded: {block.get('tool_name')}]")
            elif "text" in block:
                parts.append(str(block["text"]))
        return "\n".join(p for p in parts if p)
    return str(content)


def main():
    out = open(OUT, "w")
    out.write("# Chat Transcript — Jgive Campaign Donation Page Assignment\n\n")
    out.write(
        "Exported from the Claude Code session log (JSONL). Internal extended-thinking "
        "blocks are omitted; large tool inputs/outputs are truncated for readability — the "
        "actual file contents are visible in the repo and git history instead of being "
        "duplicated here in full.\n\n---\n\n"
    )

    turn_num = 0

    with open(SRC) as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                entry = json.loads(line)
            except json.JSONDecodeError:
                continue

            etype = entry.get("type")
            if etype not in ("user", "assistant"):
                continue
            message = entry.get("message")
            if not message:
                continue
            role = message.get("role")
            content = message.get("content")

            blocks = []
            if isinstance(content, str):
                text = clean_text(content)
                if text:
                    blocks.append(("text", text))
            elif isinstance(content, list):
                for block in content:
                    if not isinstance(block, dict):
                        continue
                    btype = block.get("type")
                    if btype == "text":
                        text = clean_text(block.get("text", ""))
                        if text:
                            blocks.append(("text", text))
                    elif btype == "thinking":
                        continue
                    elif btype == "tool_use":
                        name = block.get("name", "tool")
                        try:
                            input_str = json.dumps(block.get("input", {}), indent=2)
                        except TypeError:
                            input_str = str(block.get("input"))
                        blocks.append(("tool_use", name, truncate(input_str)))
                    elif btype == "tool_result":
                        text = clean_text(tool_result_text(block.get("content")))
                        if text:
                            blocks.append(("tool_result", truncate(text)))

            if not blocks:
                continue

            turn_num += 1
            label = "User" if role == "user" else "Assistant"
            out.write(f"### {label}\n\n")
            for block in blocks:
                if block[0] == "text":
                    out.write(block[1] + "\n\n")
                elif block[0] == "tool_use":
                    _, name, input_str = block
                    out.write(f"**Tool call:** `{name}`\n\n```json\n{input_str}\n```\n\n")
                elif block[0] == "tool_result":
                    out.write(f"**Tool result:**\n\n```\n{block[1]}\n```\n\n")
            out.write("---\n\n")

    out.close()
    print(f"Wrote {turn_num} turns to {OUT}")


if __name__ == "__main__":
    main()

